namespace sv_8c672d2dee3e4bab85168dcc12919572.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_8c672d2dee3e4bab85168dcc12919572.Services;

public class InMemoryChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;
    private readonly Lock _lock = new();

    public InMemoryChatService()
    {
        _channels =
        [
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and questions", 1),
            new(3, "design", "Design reviews and feedback", 0),
            new(4, "random", "Off-topic conversations", 5),
        ];

        var now = DateTime.Now;
        _messages =
        [
            new(1, 1, "Alice", "Hey everyone! Welcome to the new chat app.", now.AddHours(-4), null,
                [new("👍", ["Bob", "Carol"]), new("🎉", ["Dave"])]),
            new(2, 1, "Bob", "Thanks Alice! This looks great.", now.AddHours(-3.5), null, []),
            new(3, 1, "Carol", "I have a question about the onboarding process. Can someone help?", now.AddHours(-3), null,
                [new("👀", ["Alice"])]),
            new(4, 1, "Dave", "Sure Carol, what do you need?", now.AddHours(-2.8), 3, []),
            new(5, 1, "Carol", "Where can I find the setup docs?", now.AddHours(-2.7), 3, []),
            new(6, 1, "Alice", "Check the wiki under Getting Started.", now.AddHours(-2.5), 3, [new("👍", ["Carol"])]),
            new(7, 1, "Bob", "Has anyone tried the new build pipeline?", now.AddHours(-2), null, []),
            new(8, 1, "Dave", "Yes, it's much faster now!", now.AddHours(-1.5), 7, []),
            new(9, 1, "Alice", "Agreed, great improvement.", now.AddHours(-1), 7, [new("❤️", ["Bob"])]),
            new(10, 1, "Carol", "Team standup in 10 minutes!", now.AddMinutes(-30), null, []),
            new(11, 1, "Bob", "On my way!", now.AddMinutes(-25), null, []),
            new(12, 1, "Dave", "Let's ship this feature today 🚀", now.AddMinutes(-5), null,
                [new("🎉", ["Alice", "Bob", "Carol"])]),

            new(13, 2, "Alice", "Deploying v2.3 to staging now.", now.AddHours(-6), null, []),
            new(14, 2, "Bob", "CI is green, looking good.", now.AddHours(-5), null, [new("👍", ["Alice"])]),
            new(15, 2, "Dave", "Found a bug in the auth module.", now.AddHours(-1), null, [new("😮", ["Bob"])]),
            new(16, 2, "Alice", "Can you file an issue?", now.AddMinutes(-45), 15, []),
            new(17, 2, "Dave", "Done, issue #342.", now.AddMinutes(-40), 15, [new("👍", ["Alice"])]),

            new(18, 3, "Carol", "New mockups are ready for review.", now.AddHours(-8), null,
                [new("👀", ["Alice", "Bob"])]),
            new(19, 3, "Alice", "Love the color palette!", now.AddHours(-7), 18, []),
            new(20, 3, "Bob", "The navigation feels cleaner.", now.AddHours(-6.5), 18, []),

            new(21, 4, "Dave", "Anyone up for lunch?", now.AddHours(-2), null, [new("🎉", ["Carol"])]),
            new(22, 4, "Carol", "I'm in! Where?", now.AddHours(-1.8), null, []),
            new(23, 4, "Bob", "Check out this meme 😂", now.AddMinutes(-15), null,
                [new("😂", ["Alice", "Dave", "Carol"])]),
        ];

        _nextMessageId = 24;
    }

    public Task<List<Channel>> GetChannelsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_channels.Select(c => c with { }).ToList());
        }
    }

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        lock (_lock)
        {
            var channelMessages = _messages
                .Where(m => m.ChannelId == channelId && m.ReplyToId is null)
                .OrderBy(m => m.SentAt)
                .ToList();

            var result = channelMessages
                .Skip(Math.Max(0, channelMessages.Count - skip - take))
                .Take(take)
                .ToList();

            return Task.FromResult(result);
        }
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        lock (_lock)
        {
            var message = new Message(_nextMessageId++, channelId, "You", content, DateTime.Now, replyToId, []);
            _messages.Add(message);
            return Task.FromResult(message);
        }
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        lock (_lock)
        {
            var replies = _messages
                .Where(m => m.ReplyToId == rootMessageId)
                .OrderBy(m => m.SentAt)
                .ToList();

            return Task.FromResult(replies);
        }
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        lock (_lock)
        {
            var index = _messages.FindIndex(m => m.Id == messageId);
            if (index < 0) return Task.CompletedTask;

            var message = _messages[index];
            var reactions = message.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == emoji);

            if (existing >= 0)
            {
                var reaction = reactions[existing];
                if (!reaction.Users.Contains("You"))
                {
                    reactions[existing] = reaction with { Users = [.. reaction.Users, "You"] };
                }
            }
            else
            {
                reactions.Add(new Reaction(emoji, ["You"]));
            }

            _messages[index] = message with { Reactions = reactions };
            return Task.CompletedTask;
        }
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        lock (_lock)
        {
            var index = _channels.FindIndex(c => c.Id == channelId);
            if (index >= 0)
            {
                _channels[index] = _channels[index] with { UnreadCount = 0 };
            }

            return Task.CompletedTask;
        }
    }
}

