    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e3e5e8;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    background: none;
