@using sv_8c672d2dee3e4bab85168dcc12919572.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list" @ref="_listRef">
    @if (HasMoreMessages)
    {
        <div class="load-more">
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnLoadMore" disabled="@IsLoadingMore">
                @if (IsLoadingMore)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    <span>Loading...</span>
                }
                else
                {
                    <span>⬆ Load older messages</span>
                }
            </button>
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ThreadReplyCount="GetThreadReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference _listRef;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<MessageList>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageList.razor.js");
            await _jsModule.InvokeVoidAsync("init", _listRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        if (HasMoreMessages && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("dispose");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.load-more {
    text-align: center;
    padding: 8px;
}

let scrollHandler = null;
let targetElement = null;

export function init(element, dotNetRef) {
    targetElement = element;
    scrollHandler = () => {
        if (element.scrollTop <= 5) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    };
    element.addEventListener('scroll', scrollHandler);
    // Auto-scroll to bottom on initial load
    element.scrollTop = element.scrollHeight;
}

export function dispose() {
    if (targetElement && scrollHandler) {
        targetElement.removeEventListener('scroll', scrollHandler);
        scrollHandler = null;
        targetElement = null;
    }
}

