@using sv_8c672d2dee3e4bab85168dcc12919572.Services

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@MessageItem.FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..." ButtonText="Reply" OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    width: 100%;
    height: 100%;
    background: #f9fafb;
    border-left: 1px solid #e3e5e8;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e3e5e8;
    flex-shrink: 0;
}

.thread-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #2e3338;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    color: #72767d;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #e3e5e8;
    color: #2e3338;
}

.thread-root {
    padding: 12px 16px;
    background: #fff;
    border-bottom: 1px solid #e3e5e8;
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #2e3338;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.88rem;
    color: #4f5660;
    line-height: 1.4;
}

.thread-divider {
    padding: 6px 16px;
    font-size: 0.75rem;
    color: #72767d;
    border-bottom: 1px solid #e3e5e8;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #2e3338;
}

.reply-time {
    font-size: 0.72rem;
    color: #72767d;
}

.reply-content {
    font-size: 0.85rem;
    color: #2e3338;
    line-height: 1.4;
}

