arguments.file_text:
@inherits LayoutComponentBase

<div class="chat-page-root">
    @Body
</div>

.chat-page-root {
    width: 100vw;
    height: 100vh;
    overflow: hidden;
    margin: 0;
    padding: 0;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_8c672d2dee3e4bab85168dcc12919572.Services
@using sv_8c672d2dee3e4bab85168dcc12919572.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         HasMoreMessages="_hasMoreMessages"
                         IsLoadingMore="_isLoadingMore"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage" />
        }
    </div>

    @if (_isThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private Channel? _selectedChannel;
    private int _selectedChannelId;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];
    private bool _hasMoreMessages;
    private bool _isLoadingMore;
    private int _loadedCount;
    private const int PageSize = 20;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _loadedCount = 0;
        _messages = [];
        _threadSummaries = [];
        CloseThread();

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMessages()
    {
        var loaded = await ChatService.GetMessagesAsync(_selectedChannelId, _loadedCount, PageSize);
        if (loaded.Count > 0)
        {
            _messages.InsertRange(0, loaded);
            _loadedCount += loaded.Count;
        }
        _hasMoreMessages = loaded.Count == PageSize;

        foreach (var msg in loaded)
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            if (thread.Count > 0)
            {
                _threadSummaries[msg.Id] = new ThreadSummary(
                    msg.Id, thread.Count, thread[^1].SentAt);
            }
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore) return;
        _isLoadingMore = true;
        await LoadMessages();
        _isLoadingMore = false;
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _isThreadOpen = true;
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        _messages = await ChatService.GetMessagesAsync(_selectedChannelId, 0, _loadedCount);
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(msg);
        _loadedCount++;
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id, _threadReplies.Count, reply.SentAt);
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
}

.chat-sidebar {
    width: 240px;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    overflow: hidden;
}

.chat-thread {
    width: 340px;
    min-width: 280px;
    flex-shrink: 0;
}

